@page "/profile"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h2>Roles</h2>
        <ul>
            @foreach (var role in GetRoles(context.User))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@code {
    private static IEnumerable<string> GetRoles(System.Security.Claims.ClaimsPrincipal user)
    {
        return user.Claims
            .Where(c => c.Type == System.Security.Claims.ClaimTypes.Role)
            .Select(c => c.Value);
    }
}

